import React, { useState, useEffect } from 'react';
import { Outlet, Link, useLocation } from 'react-router-dom';

const navigation = [
  { name: 'Blockchain', path: '/blockchain', icon: '' },
  { name: 'Web3', path: '/web3', icon: '' },
];

function Layout() {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);
  const location = useLocation();

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth < 768);
      if (window.innerWidth >= 768) {
        setSidebarOpen(true);
      } else {
        setSidebarOpen(false);
      }
    };

    window.addEventListener('resize', handleResize);
    handleResize();

    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const toggleSidebar = () => {
    setSidebarOpen(!sidebarOpen);
  };

  const closeSidebar = () => {
    if (isMobile) {
      setSidebarOpen(false);
    }
  };

  return (
    <div style={{ 
      display: 'flex', 
      minHeight: '100vh', 
      background: '#0A0F1A',
      overflow: 'hidden'
    }}>
      {/* Overlay pour mobile */}
      {isMobile && sidebarOpen && (
        <div
          onClick={closeSidebar}
          style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: 'rgba(0,0,0,0.6)',
            zIndex: 999,
            backdropFilter: 'blur(4px)'
          }}
        />
      )}

      {/* Sidebar */}
      <div style={{
        width: isMobile ? (sidebarOpen ? '280px' : '0px') : '240px',
        background: '#1A2332',
        borderRight: '1px solid #2A3A4A',
        transition: 'width 0.3s ease-in-out, transform 0.3s ease-in-out',
        overflow: 'hidden',
        position: isMobile ? 'fixed' : 'sticky',
        top: 0,
        left: 0,
        height: '100vh',
        zIndex: 1000,
        transform: isMobile && !sidebarOpen ? 'translateX(-100%)' : 'translateX(0)',
        display: 'flex',
        flexDirection: 'column'
      }}>
        <div style={{ 
          padding: '20px',
          borderBottom: '1px solid #2A3A4A',
          flexShrink: 0
        }}>
          <div style={{ 
            display: 'flex', 
            justifyContent: 'space-between', 
            alignItems: 'center',
            marginBottom: '20px'
          }}>
            <h1 style={{ 
              color: '#3B82F6', 
              fontSize: isMobile ? '18px' : '20px',
              margin: 0
            }}>
               CyberSec
            </h1>
            {isMobile && (
              <button
                onClick={closeSidebar}
                style={{
                  background: 'transparent',
                  border: 'none',
                  color: '#94A3B8',
                  fontSize: '24px',
                  cursor: 'pointer',
                  padding: '0 8px'
                }}
              >

              </button>
            )}
          </div>
          <p style={{ 
            color: '#94A3B8', 
            fontSize: '12px',
            margin: 0
          }}>
            Security Platform v5.0
          </p>
        </div>

        <nav style={{ 
          padding: '16px',
          flex: 1,
          overflowY: 'auto'
        }}>
          {navigation.map((item) => (
            <Link
              key={item.path}
              to={item.path}
              onClick={closeSidebar}
              style={{
                display: 'flex',
                alignItems: 'center',
                padding: '12px 16px',
                marginBottom: '8px',
                borderRadius: '8px',
                textDecoration: 'none',
                color: location.pathname === item.path ? '#3B82F6' : '#94A3B8',
                background: location.pathname === item.path ? 'rgba(59, 130, 246, 0.1)' : 'transparent',
                transition: 'all 0.2s',
                cursor: 'pointer',
                fontSize: isMobile ? '15px' : '14px'
              }}
            >
              <span style={{ marginRight: '12px', fontSize: '18px' }}>{item.icon}</span>
              {item.name}
            </Link>
          ))}
        </nav>

        <div style={{
          padding: '16px',
          borderTop: '1px solid #2A3A4A',
          flexShrink: 0
        }}>
          <div style={{
            display: 'flex',
            alignItems: 'center',
            gap: '12px',
            padding: '8px 12px',
            background: 'rgba(59, 130, 246, 0.05)',
            borderRadius: '8px'
          }}>
            <div style={{
              width: '32px',
              height: '32px',
              borderRadius: '50%',
              background: '#3B82F6',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '14px',
              fontWeight: 'bold',
              color: '#FFFFFF',
              flexShrink: 0
            }}>
              A
            </div>
            <div style={{ overflow: 'hidden' }}>
              <p style={{ 
                color: '#FFFFFF', 
                fontSize: '13px',
                margin: 0,
                whiteSpace: 'nowrap',
                overflow: 'hidden',
                textOverflow: 'ellipsis'
              }}>
                Admin
              </p>
              <p style={{ 
                color: '#94A3B8', 
                fontSize: '11px',
                margin: 0
              }}>
                Online
              </p>
            </div>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div style={{
        flex: 1,
        padding: isMobile ? '12px' : '20px',
        marginLeft: isMobile ? 0 : 0,
        minHeight: '100vh',
        width: '100%',
        maxWidth: '100%',
        overflowX: 'hidden'
      }}>
        {/* Header */}
        <header style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          padding: isMobile ? '12px 16px' : '16px 24px',
          background: '#1A2332',
          borderRadius: '12px',
          marginBottom: '24px',
          border: '1px solid #2A3A4A',
          flexWrap: 'wrap',
          gap: '12px'
        }}>
          <button
            onClick={toggleSidebar}
            style={{
              background: 'transparent',
              border: 'none',
              color: '#94A3B8',
              fontSize: isMobile ? '22px' : '24px',
              cursor: 'pointer',
              padding: '4px 8px'
            }}
          >

          </button>
          <div style={{
            display: 'flex',
            alignItems: 'center',
            gap: '12px',
            flexWrap: 'wrap'
          }}>
            <span style={{ 
              color: '#94A3B8',
              fontSize: isMobile ? '14px' : '16px'
            }}>

            </span>
            <span style={{ 
              color: '#3B82F6',
              fontSize: isMobile ? '14px' : '16px',
              fontWeight: '500'
            }}>
              Admin
            </span>
          </div>
        </header>

        {/* Page Content */}
        <main style={{
          width: '100%',
          maxWidth: '100%',
          overflowX: 'hidden'
        }}>
          <Outlet />
        </main>
      </div>
    </div>
  );
}

export default Layout;
